--!strict
-- RatUI v2 - original Mercury-inspired layout with improved HUD/keybind/watermark
local Players = game:GetService("Players")
local RunService = game:GetService("RunService")
local TweenService = game:GetService("TweenService")
local UserInputService = game:GetService("UserInputService")
local Lighting = game:GetService("Lighting")
local Stats = game:GetService("Stats")
local LocalPlayer = Players.LocalPlayer

local RatUI = {}
RatUI.__index = RatUI
local Window = {}
Window.__index = Window
local Tab = {}
Tab.__index = Tab

local function new(className, props, children)
    local i = Instance.new(className)
    for k, v in pairs(props or {}) do i[k] = v end
    for _, c in ipairs(children or {}) do c.Parent = i end
    return i
end

local function uiCorner(r) return new("UICorner", { CornerRadius = UDim.new(0, r) }) end
local function uiStroke(c, t, tr) return new("UIStroke", { Color = c, Thickness = t or 1, Transparency = tr or 0, ApplyStrokeMode = Enum.ApplyStrokeMode.Border }) end
local function uiList(padding) return new("UIListLayout", { Padding = UDim.new(0, padding or 0), SortOrder = Enum.SortOrder.LayoutOrder }) end
local function uiPad(v) return new("UIPadding", { PaddingTop = UDim.new(0, v), PaddingBottom = UDim.new(0, v), PaddingLeft = UDim.new(0, v), PaddingRight = UDim.new(0, v) }) end

local function formatClock(s)
    local h = math.floor(s / 3600)
    local m = math.floor((s % 3600) / 60)
    local sec = math.floor(s % 60)
    return string.format("%02d:%02d:%02d", h, m, sec)
end

local function makeDraggable(handle, root)
    local dragStart, startPos
    handle.InputBegan:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then
            dragStart = input.Position
            startPos = root.Position
        end
    end)
    UserInputService.InputEnded:Connect(function(input)
        if input.UserInputType == Enum.UserInputType.MouseButton1 then dragStart = nil startPos = nil end
    end)
    UserInputService.InputChanged:Connect(function(input)
        if not dragStart or not startPos then return end
        if input.UserInputType ~= Enum.UserInputType.MouseMovement then return end
        local d = input.Position - dragStart
        root.Position = UDim2.new(startPos.X.Scale, startPos.X.Offset + d.X, startPos.Y.Scale, startPos.Y.Offset + d.Y)
    end)
end

RatUI.DefaultTheme = {
    Bg = Color3.fromRGB(10, 13, 21),
    Surface = Color3.fromRGB(19, 25, 37),
    Surface2 = Color3.fromRGB(30, 37, 53),
    Accent = Color3.fromRGB(96, 166, 255),
    Text = Color3.fromRGB(240, 245, 255),
    Sub = Color3.fromRGB(142, 158, 188),
    Good = Color3.fromRGB(101, 236, 170),
    Bad = Color3.fromRGB(252, 102, 122),
}

function RatUI.new(config)
    config = config or {}
    local self = setmetatable({}, RatUI)
    self.Theme = config.Theme or RatUI.DefaultTheme
    self.ScriptName = config.ScriptName or "RatUI"
    self.ToggleKey = config.ToggleKey or Enum.KeyCode.RightShift
    self._windows = {}
    self._connections = {}
    self._start = os.clock()
    self._fpsFrames = 0
    self._fpsAcc = 0
    self._fps = 0
    return self
end

function RatUI:CreateWindow(options)
    options = options or {}
    local w = setmetatable({}, Window)
    w._ui = self
    w.Theme = options.Theme or self.Theme
    w.Title = options.Title or "RatUI"
    w.Subtitle = options.Subtitle or "original custom layout"
    w._tabs = {}
    w._keybinds = {}
    w._listening = nil
    w._activeTab = nil

    local playerGui = LocalPlayer:WaitForChild("PlayerGui")
    w.Gui = new("ScreenGui", { Name = "RatUI", IgnoreGuiInset = true, ResetOnSpawn = false, Parent = playerGui })
    w.Root = new("Frame", { BackgroundTransparency = 1, Size = UDim2.fromScale(1,1), Parent = w.Gui })

    w.Blur = new("BlurEffect", { Name = "RatUI_Blur", Parent = Lighting, Enabled = options.Blur ~= false, Size = options.BlurSize or 10 })

    -- WATERMARK (improved)
    w.Watermark = new("Frame", { AnchorPoint = Vector2.new(1,0), Position = UDim2.new(1,-16,0,12), Size = UDim2.fromOffset(490, 42), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Root }, { uiCorner(10), uiStroke(w.Theme.Accent, 1, 0.25) })
    new("Frame", { Size = UDim2.fromOffset(4, 42), BackgroundColor3 = w.Theme.Accent, BorderSizePixel = 0, Parent = w.Watermark }, { uiCorner(10) })
    w.WatermarkText = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,0), Size = UDim2.new(1,-16,1,0), Font = Enum.Font.GothamSemibold, Text = "", RichText = true, TextSize = 13, TextColor3 = w.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.Watermark })

    -- MAIN WINDOW
    w.Main = new("Frame", { AnchorPoint = Vector2.new(0.5,0.5), Position = UDim2.fromScale(0.5,0.53), Size = UDim2.fromOffset(980, 600), BackgroundColor3 = w.Theme.Bg, BorderSizePixel = 0, Parent = w.Root }, { uiCorner(14), uiStroke(w.Theme.Accent, 1, 0.5) })
    w.Top = new("Frame", { Size = UDim2.new(1,0,0,52), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Main }, { uiCorner(14) })
    new("Frame", { Position = UDim2.new(0,0,1,-14), Size = UDim2.new(1,0,0,14), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Top })
    w.TitleLabel = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(18,0), Size = UDim2.fromOffset(260,52), Font = Enum.Font.GothamBold, Text = w.Title, TextSize = 16, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = w.Theme.Text, Parent = w.Top })
    w.SubLabel = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(180,0), Size = UDim2.fromOffset(420,52), Font = Enum.Font.Gotham, Text = w.Subtitle, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = w.Theme.Sub, Parent = w.Top })
    w.ToggleInfo = new("TextLabel", { BackgroundTransparency = 1, AnchorPoint = Vector2.new(1,0), Position = UDim2.new(1,-16,0,0), Size = UDim2.fromOffset(230,52), Font = Enum.Font.GothamSemibold, Text = "Toggle: " .. self.ToggleKey.Name, TextSize = 12, TextXAlignment = Enum.TextXAlignment.Right, TextColor3 = w.Theme.Sub, Parent = w.Top })
    new("Frame", { Position = UDim2.fromOffset(16,50), Size = UDim2.new(1,-32,0,1), BackgroundColor3 = w.Theme.Accent, BackgroundTransparency = 0.5, BorderSizePixel = 0, Parent = w.Top })

    -- tabs moved to the right side
    w.Side = new("Frame", { AnchorPoint = Vector2.new(1, 0), Position = UDim2.new(1,-12,0,62), Size = UDim2.new(0,198,1,-74), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Main }, { uiCorner(12), uiStroke(w.Theme.Surface2, 1, 0.4) })
    w.SideList = new("ScrollingFrame", { BackgroundTransparency = 1, BorderSizePixel = 0, Position = UDim2.fromOffset(8,8), Size = UDim2.new(1,-16,1,-16), ScrollBarThickness = 2, CanvasSize = UDim2.new(0,0,0,0), AutomaticCanvasSize = Enum.AutomaticSize.Y, Parent = w.Side }, { uiList(6) })

    w.Body = new("Frame", { Position = UDim2.fromOffset(12,62), Size = UDim2.new(1,-222,1,-74), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Main }, { uiCorner(12), uiStroke(w.Theme.Surface2, 1, 0.4) })

    -- TARGET HUD (improved)
    w.Target = new("Frame", { Position = UDim2.fromOffset(16,62), Size = UDim2.fromOffset(360, 148), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Root }, { uiCorner(11), uiStroke(w.Theme.Accent, 1, 0.3) })
    new("TextLabel", { Name = "Header", BackgroundTransparency = 1, Position = UDim2.fromOffset(14,8), Size = UDim2.new(1,-28,0,18), Font = Enum.Font.GothamSemibold, Text = "TARGET HUD", TextSize = 11, TextColor3 = w.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.Target })
    w.TargetName = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(14,24), Size = UDim2.new(1,-28,0,24), Font = Enum.Font.GothamBold, Text = "No target", TextSize = 16, TextColor3 = w.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.Target })
    w.TargetDistance = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(14,47), Size = UDim2.new(1,-28,0,18), Font = Enum.Font.Gotham, Text = "Distance: --", TextSize = 12, TextColor3 = w.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.Target })
    w.TargetHealthBack = new("Frame", { Position = UDim2.fromOffset(14,74), Size = UDim2.new(1,-28,0,20), BackgroundColor3 = w.Theme.Surface2, BorderSizePixel = 0, Parent = w.Target }, { uiCorner(9) })
    w.TargetHealthFill = new("Frame", { Size = UDim2.fromScale(0,1), BackgroundColor3 = w.Theme.Good, BorderSizePixel = 0, Parent = w.TargetHealthBack }, { uiCorner(9) })
    w.TargetHealthText = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(14,98), Size = UDim2.new(1,-28,0,18), Font = Enum.Font.GothamSemibold, Text = "Health: --", TextSize = 12, TextColor3 = w.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.Target })

    -- custom extra: tiny session panel
    w.SessionHud = new("Frame", { Position = UDim2.fromOffset(16,220), Size = UDim2.fromOffset(240, 74), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Root }, { uiCorner(11), uiStroke(w.Theme.Accent, 1, 0.35) })
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,8), Size = UDim2.new(1,-24,0,16), Font = Enum.Font.GothamSemibold, Text = "Session Pulse", TextSize = 12, TextColor3 = w.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.SessionHud })
    w.SessionText = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,26), Size = UDim2.new(1,-24,0,20), Font = Enum.Font.GothamBold, Text = "Players: --", TextSize = 14, TextColor3 = w.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.SessionHud })
    w.SessionClock = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,46), Size = UDim2.new(1,-24,0,18), Font = Enum.Font.Gotham, Text = "Clock: --", TextSize = 12, TextColor3 = w.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.SessionHud })

    -- KEYBIND LIST (improved)
    w.KeybindHud = new("Frame", { AnchorPoint = Vector2.new(1,1), Position = UDim2.new(1,-16,1,-16), Size = UDim2.fromOffset(340, 238), BackgroundColor3 = w.Theme.Surface, BorderSizePixel = 0, Parent = w.Root }, { uiCorner(11), uiStroke(w.Theme.Accent, 1, 0.3) })
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,8), Size = UDim2.new(1,-24,0,22), Font = Enum.Font.GothamBold, Text = "Keybind List", TextSize = 14, TextColor3 = w.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.KeybindHud })
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(12,26), Size = UDim2.new(1,-24,0,16), Font = Enum.Font.Gotham, Text = "Mode / key / live state", TextSize = 11, TextColor3 = w.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = w.KeybindHud })
    w.KeybindList = new("ScrollingFrame", { BackgroundTransparency = 1, BorderSizePixel = 0, Position = UDim2.fromOffset(12,46), Size = UDim2.new(1,-24,1,-56), ScrollBarThickness = 2, CanvasSize = UDim2.new(0,0,0,0), AutomaticCanvasSize = Enum.AutomaticSize.Y, Parent = w.KeybindHud }, { uiList(5) })

    makeDraggable(w.Top, w.Main)
    makeDraggable(w.Target, w.Target)
    makeDraggable(w.KeybindHud, w.KeybindHud)

    table.insert(self._windows, w)
    w:_connect()
    return w
end

function Window:_connect()
    local ui = self._ui

    table.insert(ui._connections, UserInputService.InputBegan:Connect(function(input, gp)
        if gp then return end

        if self._listening then
            if input.UserInputType == Enum.UserInputType.Keyboard then
                self._listening.Key = input.KeyCode
                if self._listening.Button then self._listening.Button.Text = input.KeyCode.Name end
                self:_renderKeybinds()
            end
            self._listening = nil
            return
        end

        if input.KeyCode == ui.ToggleKey then
            self.Main.Visible = not self.Main.Visible
            return
        end

        for _, bind in ipairs(self._keybinds) do
            if bind.Key == input.KeyCode then
                if bind.Mode == "Hold" then
                    bind.Active = true
                    if bind.Callback then bind.Callback(true) end
                else
                    bind.Active = not bind.Active
                    if bind.Callback then bind.Callback(bind.Active) end
                end
                self:_renderKeybinds()
            end
        end
    end))

    table.insert(ui._connections, UserInputService.InputEnded:Connect(function(input, gp)
        if gp then return end
        for _, bind in ipairs(self._keybinds) do
            if bind.Key == input.KeyCode and bind.Mode == "Hold" then
                bind.Active = false
                if bind.Callback then bind.Callback(false) end
                self:_renderKeybinds()
            end
        end
    end))

    table.insert(ui._connections, RunService.RenderStepped:Connect(function(dt)
        ui._fpsFrames += 1
        ui._fpsAcc += dt
        if ui._fpsAcc >= 0.25 then
            ui._fps = math.floor(ui._fpsFrames / ui._fpsAcc + 0.5)
            ui._fpsFrames = 0
            ui._fpsAcc = 0
            local uptime = formatClock(os.clock() - ui._start)
            local ping = 0
            pcall(function() ping = math.floor(Stats.Network.ServerStatsItem["Data Ping"]:GetValue()) end)
            local accent = self.Theme.Accent
            self.WatermarkText.Text = string.format('<font color="rgb(%d,%d,%d)">%s</font> • FPS %d • Ping %dms • Uptime %s', math.floor(accent.R*255), math.floor(accent.G*255), math.floor(accent.B*255), ui.ScriptName, ui._fps, ping, uptime)
            self.SessionText.Text = string.format("Players: %d", #Players:GetPlayers())
            self.SessionClock.Text = string.format("Clock: %s", os.date("!%H:%M:%S UTC"))
        end
    end))

    self:_renderKeybinds()
end

function Window:_setTab(tab)
    self._activeTab = tab
    for _, t in ipairs(self._tabs) do
        local active = t == tab
        t.Button.BackgroundColor3 = active and self.Theme.Accent or self.Theme.Surface2
        t.Button.TextColor3 = active and Color3.new(1,1,1) or self.Theme.Text
        t.Page.Visible = active
    end
end

function Window:CreateTab(name, icon)
    local tab = setmetatable({}, Tab)
    tab._w = self
    tab.Name = name

    tab.Button = new("TextButton", {
        AutoButtonColor = false,
        Size = UDim2.new(1,0,0,38),
        BackgroundColor3 = self.Theme.Surface2,
        BorderSizePixel = 0,
        Text = string.format("%s  %s", icon or "◈", string.upper(name)),
        Font = Enum.Font.GothamBold,
        TextSize = 12,
        TextXAlignment = Enum.TextXAlignment.Center,
        TextColor3 = self.Theme.Text,
        Parent = self.SideList
    }, { uiCorner(10), uiStroke(self.Theme.Accent, 1, 0.8) })

    tab.Page = new("ScrollingFrame", { BackgroundTransparency = 1, BorderSizePixel = 0, Position = UDim2.fromOffset(10,10), Size = UDim2.new(1,-20,1,-20), ScrollBarThickness = 3, CanvasSize = UDim2.new(0,0,0,0), AutomaticCanvasSize = Enum.AutomaticSize.Y, Visible = false, Parent = self.Body }, { uiList(8) })

    tab.Button.MouseButton1Click:Connect(function() self:_setTab(tab) end)
    table.insert(self._tabs, tab)
    if #self._tabs == 1 then self:_setTab(tab) end
    return tab
end

function Tab:_card(h)
    return new("Frame", { Size = UDim2.new(1,0,0,h), BackgroundColor3 = self._w.Theme.Surface2, BorderSizePixel = 0, Parent = self.Page }, { uiCorner(10), uiStroke(self._w.Theme.Surface,1,0.45) })
end

function Tab:AddButton(text, callback)
    local c = self:_card(46)
    local b = new("TextButton", { AutoButtonColor = false, Position = UDim2.fromOffset(6,6), Size = UDim2.new(1,-12,1,-12), BackgroundColor3 = self._w.Theme.Accent, BorderSizePixel = 0, Text = text, Font = Enum.Font.GothamBold, TextSize = 13, TextColor3 = Color3.new(1,1,1), Parent = c }, { uiCorner(8) })
    b.MouseButton1Click:Connect(function() if callback then callback() end end)
    return b
end

function Tab:AddToggle(text, defaultState, callback)
    local state = defaultState == true
    local c = self:_card(50)
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,0), Size = UDim2.new(1,-80,1,0), Text = text, Font = Enum.Font.GothamSemibold, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = self._w.Theme.Text, Parent = c })
    local sw = new("TextButton", { AutoButtonColor = false, AnchorPoint = Vector2.new(1,0.5), Position = UDim2.new(1,-10,0.5,0), Size = UDim2.fromOffset(46,24), BackgroundColor3 = state and self._w.Theme.Accent or self._w.Theme.Surface, BorderSizePixel = 0, Text = "", Parent = c }, { uiCorner(20) })
    local k = new("Frame", { Size = UDim2.fromOffset(18,18), Position = state and UDim2.fromOffset(25,3) or UDim2.fromOffset(3,3), BackgroundColor3 = Color3.new(1,1,1), BorderSizePixel = 0, Parent = sw }, { uiCorner(20) })
    local function apply()
        TweenService:Create(sw, TweenInfo.new(0.14), { BackgroundColor3 = state and self._w.Theme.Accent or self._w.Theme.Surface }):Play()
        TweenService:Create(k, TweenInfo.new(0.14), { Position = state and UDim2.fromOffset(25,3) or UDim2.fromOffset(3,3) }):Play()
        if callback then callback(state) end
    end
    sw.MouseButton1Click:Connect(function() state = not state apply() end)
    apply()
    return { Get = function() return state end, Set = function(_, v) state = v and true or false apply() end }
end

function Tab:AddSlider(text, min, max, defaultValue, callback)
    min = min or 0
    max = max or 100
    local value = math.clamp(defaultValue or min, min, max)
    local c = self:_card(74)
    local title = new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,6), Size = UDim2.new(1,-20,0,20), Text = text, Font = Enum.Font.GothamSemibold, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = self._w.Theme.Text, Parent = c })
    local track = new("Frame", { Position = UDim2.fromOffset(10,38), Size = UDim2.new(1,-20,0,22), BackgroundColor3 = self._w.Theme.Surface, BorderSizePixel = 0, Parent = c }, { uiCorner(10) })
    local fill = new("Frame", { Size = UDim2.fromScale(0,1), BackgroundColor3 = self._w.Theme.Accent, BorderSizePixel = 0, Parent = track }, { uiCorner(10) })
    local drag = false
    local function redraw()
        local alpha = (value - min) / (max - min)
        fill.Size = UDim2.fromScale(alpha, 1)
        title.Text = string.format("%s: %.1f", text, value)
        if callback then callback(value) end
    end
    local function setFromX(x)
        local alpha = math.clamp((x - track.AbsolutePosition.X) / track.AbsoluteSize.X, 0, 1)
        value = min + (max - min) * alpha
        redraw()
    end
    track.InputBegan:Connect(function(i) if i.UserInputType == Enum.UserInputType.MouseButton1 then drag = true setFromX(i.Position.X) end end)
    UserInputService.InputChanged:Connect(function(i) if drag and i.UserInputType == Enum.UserInputType.MouseMovement then setFromX(i.Position.X) end end)
    UserInputService.InputEnded:Connect(function(i) if i.UserInputType == Enum.UserInputType.MouseButton1 then drag = false end end)
    redraw()
    return { Get = function() return value end, Set = function(_, v) value = math.clamp(v, min, max) redraw() end }
end

function Tab:AddDropdown(text, options, defaultOption, callback)
    options = options or {}
    local selected = defaultOption or options[1] or "None"
    local open = false
    local c = self:_card(96)
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,6), Size = UDim2.new(1,-20,0,20), Text = text, Font = Enum.Font.GothamSemibold, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = self._w.Theme.Text, Parent = c })
    local main = new("TextButton", { AutoButtonColor = false, Position = UDim2.fromOffset(10,32), Size = UDim2.new(1,-20,0,30), BackgroundColor3 = self._w.Theme.Surface, BorderSizePixel = 0, Text = tostring(selected), Font = Enum.Font.GothamBold, TextSize = 12, TextColor3 = self._w.Theme.Text, Parent = c }, { uiCorner(8) })
    local list = new("Frame", { Visible = false, Position = UDim2.fromOffset(10,66), Size = UDim2.new(1,-20,0,24 * #options), BackgroundColor3 = self._w.Theme.Surface, BorderSizePixel = 0, Parent = c }, { uiCorner(8), uiList(4), uiPad(4) })
    local function set(v)
        selected = v
        main.Text = tostring(v)
        if callback then callback(v) end
    end
    for _, option in ipairs(options) do
        local row = new("TextButton", { AutoButtonColor = false, Size = UDim2.new(1,0,0,20), BackgroundColor3 = self._w.Theme.Surface2, BorderSizePixel = 0, Text = tostring(option), Font = Enum.Font.Gotham, TextSize = 12, TextColor3 = self._w.Theme.Text, Parent = list }, { uiCorner(6) })
        row.MouseButton1Click:Connect(function() open = false list.Visible = false set(option) end)
    end
    main.MouseButton1Click:Connect(function()
        open = not open
        list.Visible = open
    end)
    set(selected)
    return { Get = function() return selected end, Set = function(_, v) set(v) end }
end

function Tab:AddTextbox(text, defaultValue, callback)
    local c = self:_card(58)
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,0), Size = UDim2.new(0.45,0,1,0), Text = text, Font = Enum.Font.GothamSemibold, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = self._w.Theme.Text, Parent = c })
    local box = new("TextBox", { Position = UDim2.new(0.46,0,0.5,-15), Size = UDim2.new(0.54,-10,0,30), BackgroundColor3 = self._w.Theme.Surface, BorderSizePixel = 0, Text = tostring(defaultValue or ""), PlaceholderText = "Type...", ClearTextOnFocus = false, Font = Enum.Font.Gotham, TextSize = 12, TextColor3 = self._w.Theme.Text, Parent = c }, { uiCorner(7) })
    box.FocusLost:Connect(function(enterPressed)
        if callback then callback(box.Text, enterPressed) end
    end)
    return box
end

function Tab:AddKeybind(text, key, mode, callback)
    local bind = { Name = text, Key = key or Enum.KeyCode.Unknown, Mode = mode or "Toggle", Active = false, Callback = callback }
    local c = self:_card(60)
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,0), Size = UDim2.new(0.6,0,1,0), Text = text, Font = Enum.Font.GothamSemibold, TextSize = 13, TextXAlignment = Enum.TextXAlignment.Left, TextColor3 = self._w.Theme.Text, Parent = c })
    local m = new("TextLabel", { BackgroundTransparency = 1, AnchorPoint = Vector2.new(1,0.5), Position = UDim2.new(1,-130,0.5,0), Size = UDim2.fromOffset(48,20), Text = bind.Mode, Font = Enum.Font.Gotham, TextSize = 11, TextColor3 = self._w.Theme.Sub, Parent = c })
    local b = new("TextButton", { AutoButtonColor = false, AnchorPoint = Vector2.new(1,0.5), Position = UDim2.new(1,-10,0.5,0), Size = UDim2.fromOffset(108,32), BackgroundColor3 = self._w.Theme.Surface, BorderSizePixel = 0, Text = bind.Key.Name, Font = Enum.Font.GothamBold, TextSize = 12, TextColor3 = self._w.Theme.Text, Parent = c }, { uiCorner(8), uiStroke(self._w.Theme.Surface2, 1, 0.3) })
    bind.Button = b
    bind.ModeLabel = m
    b.MouseButton1Click:Connect(function() self._w._listening = bind b.Text = "Press key..." end)
    table.insert(self._w._keybinds, bind)
    self._w:_renderKeybinds()
    return bind
end

function Window:_renderKeybinds()
    for _, child in ipairs(self.KeybindList:GetChildren()) do
        if child:IsA("Frame") or child:IsA("TextLabel") then child:Destroy() end
    end
    if #self._keybinds == 0 then
        new("TextLabel", { BackgroundTransparency = 1, Size = UDim2.new(1,0,0,20), Text = "No keybinds assigned", Font = Enum.Font.Gotham, TextSize = 12, TextColor3 = self.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = self.KeybindList })
        return
    end
    for _, bind in ipairs(self._keybinds) do
        local row = new("Frame", { Size = UDim2.new(1,0,0,28), BackgroundColor3 = bind.Active and Color3.fromRGB(35, 58, 44) or self.Theme.Surface2, BorderSizePixel = 0, Parent = self.KeybindList }, { uiCorner(7) })
        new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(8,0), Size = UDim2.new(0.58,0,1,0), Text = bind.Name, Font = Enum.Font.GothamSemibold, TextSize = 12, TextColor3 = self.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = row })
        new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.new(0.58,0,0,0), Size = UDim2.new(0.2,0,1,0), Text = bind.Mode, Font = Enum.Font.Gotham, TextSize = 11, TextColor3 = self.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, Parent = row })
        new("TextLabel", { BackgroundTransparency = 1, AnchorPoint = Vector2.new(1,0), Position = UDim2.new(1,-8,0,0), Size = UDim2.new(0.2,0,1,0), Text = bind.Key.Name .. (bind.Active and "  ON" or ""), Font = Enum.Font.GothamBold, TextSize = 11, TextColor3 = bind.Active and self.Theme.Good or self.Theme.Text, TextXAlignment = Enum.TextXAlignment.Right, Parent = row })
    end
end

function Window:SetTarget(data)
    data = data or {}
    local name = tostring(data.Name or data.name or "Unknown")
    local dist = tonumber(data.Distance or data.distance) or 0
    local hp = tonumber(data.Health or data.health) or 0
    local maxHp = math.max(tonumber(data.MaxHealth or data.maxHealth) or 100, 1)
    local ratio = math.clamp(hp / maxHp, 0, 1)
    self.TargetName.Text = name
    self.TargetDistance.Text = string.format("Distance: %.1fm", dist)
    self.TargetHealthText.Text = string.format("Health: %d / %d", math.floor(hp + 0.5), math.floor(maxHp + 0.5))
    TweenService:Create(self.TargetHealthFill, TweenInfo.new(0.16, Enum.EasingStyle.Quad, Enum.EasingDirection.Out), {
        Size = UDim2.fromScale(ratio, 1),
        BackgroundColor3 = Color3.fromRGB(255 - math.floor(140 * ratio), 80 + math.floor(140 * ratio), 110)
    }):Play()
end

function Window:ClearTarget()
    self.TargetName.Text = "No target"
    self.TargetDistance.Text = "Distance: --"
    self.TargetHealthText.Text = "Health: --"
    self.TargetHealthFill.Size = UDim2.fromScale(0,1)
end

function Window:Notify(title, message, duration)
    duration = duration or 3
    if not self.NotifyHolder then
        self.NotifyHolder = new("Frame", { AnchorPoint = Vector2.new(1,1), Position = UDim2.new(1,-16,1,-16), Size = UDim2.fromOffset(320,220), BackgroundTransparency = 1, Parent = self.Root }, { uiList(6) })
    end
    local toast = new("Frame", { Size = UDim2.new(1,0,0,62), BackgroundColor3 = self.Theme.Surface, BorderSizePixel = 0, Parent = self.NotifyHolder }, { uiCorner(9), uiStroke(self.Theme.Accent, 1, 0.25) })
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,8), Size = UDim2.new(1,-20,0,18), Text = title, Font = Enum.Font.GothamBold, TextSize = 13, TextColor3 = self.Theme.Text, TextXAlignment = Enum.TextXAlignment.Left, Parent = toast })
    new("TextLabel", { BackgroundTransparency = 1, Position = UDim2.fromOffset(10,26), Size = UDim2.new(1,-20,0,30), Text = message, Font = Enum.Font.Gotham, TextWrapped = true, TextSize = 12, TextColor3 = self.Theme.Sub, TextXAlignment = Enum.TextXAlignment.Left, TextYAlignment = Enum.TextYAlignment.Top, Parent = toast })
    task.delay(duration, function() if toast.Parent then toast:Destroy() end end)
end

function Window:SetTheme(theme)
    self.Theme = theme
    self.Main.BackgroundColor3 = theme.Bg
    self.Top.BackgroundColor3 = theme.Surface
    self.Side.BackgroundColor3 = theme.Surface
    self.Body.BackgroundColor3 = theme.Surface
    self.Watermark.BackgroundColor3 = theme.Surface
    self.Target.BackgroundColor3 = theme.Surface
    self.SessionHud.BackgroundColor3 = theme.Surface
    self.KeybindHud.BackgroundColor3 = theme.Surface
end

function Window:SetTitle(title) self.TitleLabel.Text = tostring(title) end
function Window:SetScriptName(name) self._ui.ScriptName = tostring(name) end
function Window:SetVisible(v) self.Main.Visible = v and true or false end

function Window:Destroy()
    if self.Blur then self.Blur:Destroy() end
    if self.Gui then self.Gui:Destroy() end
end

