function RatUI:GetTheme(name) return RatUI.ThemePresets[name] end
function RatUI:DestroyAll() for _, c in ipairs(self._connections) do c:Disconnect() end self._connections = {} for _, w in ipairs(self._windows) do w:Destroy() end self._windows = {} end

